            {"type": "code", "title": "Raw parameter tensors", "content": "w1 = (torch.randn(2, 16) * 0.5).requires_grad_()\nb1 = torch.zeros(16, requires_grad=True)\nw2 = (torch.randn(16, 2) * 0.5).requires_grad_()\nb2 = torch.zeros(2, requires_grad=True)"},
